import React, { useEffect, useState } from "react";
import { Link } from 'react-router-dom';
import { CButton } from "@coreui/react";
import { customStyles } from "../../../utils/tableCustomStyles";
import DataTable from "react-data-table-component";
import { deleteProduct, getProductList } from "src/components/services/ProductApi";
import { tableProductConstant } from "../tableProductConstant";
import alertPopUp from 'sweetalert2';
import withReactContent from 'sweetalert2-react-content';
import { deleteModalSwal } from "src/utils/Common";
import authService from "src/auth/auth.service";

const MySwal = withReactContent(alertPopUp);


const ProductList = () => {
    const [rowData, setRowData] = useState([]);

    useEffect(() => {
        fetchProductList();
    }, []);

    const fetchProductList = async () => {
        const response = await getProductList();
        if (response?.status === "200 OK") {
            setRowData(response?.body);
        }
    };

    const handleConfirmModal = (id) => {
        const handleConfirm = async () => {
            const swalval = await MySwal.fire(deleteModalSwal);
            if (swalval && swalval.value === true) {
                handleDeletePrduct(id)
            }
        };
        handleConfirm();
    };

    const handleDeletePrduct = async(id) => {
        const response = await deleteProduct(id);
        if(response?.status === "202 ACCEPTED"){
            fetchProductList();
        }
    }

    return (
        <div className='row'>
            <div className="col2Large">
                <DataTable
                    title="Product List"
                    columns={tableProductConstant(handleConfirmModal)}
                    data={rowData}
                    customStyles={customStyles}
                    pagination
                    paginationPerPage={10}
                    pointerOnHover
                    fixedHeader
                    noContextMenu
                    fixedHeaderScrollHeight={"calc(100vh - 226px)"}
                />
            </div>

            {authService.getPermission("PRODUCT_CREATE") && <div className='col-sm-12'>
                <Link to={"/product/create"}>
                    <CButton type="submit" color="primary" className="create-btn" style={{ float: "right" }}>
                        {"+ Create Product"}
                    </CButton>
                </Link>
            </div>}
        </div>
    );
}

export default ProductList;
